import{_ as e,a as t,b as d,c as r}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as c,o as n,c as i,a2 as p}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Redundant Backup و Read Source Switching","description":"","frontmatter":{},"headers":[],"relativePath":"fa/Other/redundant-backup-and-read-source.md","filePath":"fa/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),l={name:"fa/Other/redundant-backup-and-read-source.md"};function u(s,a,h,o,b,k){return n(),i("div",null,[...a[0]||(a[0]=[p('<h1 id="redundant-backup-و-read-source-switching" tabindex="-1">Redundant Backup و Read Source Switching <a class="header-anchor" href="#redundant-backup-و-read-source-switching" aria-label="Permalink to &quot;Redundant Backup و Read Source Switching&quot;">​</a></h1><p>Redundant backup یک copy اضافه از fileای که قبلاً upload شده ذخیره می‌کند.</p><p>هم primary file و هم backup file می‌توانند به‌عنوان read source استفاده شوند. visitors معمولاً تفاوتی حس نمی‌کنند. تنها تفاوت این است که file از کدام storage channel serve می‌شود.</p><h2 id="redundant-backup-چه-کارهایی-می‌تواند-انجام-دهد" tabindex="-1">Redundant Backup چه کارهایی می‌تواند انجام دهد <a class="header-anchor" href="#redundant-backup-چه-کارهایی-می‌تواند-انجام-دهد" aria-label="Permalink to &quot;Redundant Backup چه کارهایی می‌تواند انجام دهد&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>ذخیره copy اضافه</td><td>files را در upload channel دیگری backup می‌کند تا risk خرابی یک channel کم شود.</td></tr><tr><td>switch کردن read source</td><td>پس از موفق شدن backup، file reads را بین primary channel و backup channel جابه‌جا می‌کند.</td></tr><tr><td>single-file backup</td><td>backup گرفتن از یک file در file details page.</td></tr><tr><td>batch backup</td><td>انتخاب چند file در admin page و backup گرفتن هم‌زمان.</td></tr><tr><td>global redundant backup</td><td>backup گرفتن از files بر اساس folder از Other Settings.</td></tr></tbody></table><h2 id="redundant-backup-entry" tabindex="-1">Redundant Backup Entry <a class="header-anchor" href="#redundant-backup-entry" aria-label="Permalink to &quot;Redundant Backup Entry&quot;">​</a></h2><p>باز کنید:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Redundant Backup</span></span></code></pre></div><p><img src="'+e+'" alt="Redundant backup" loading="lazy"></p><p>این entry برای اضافه کردن backups به یک folder یا همه files به‌صورت bulk مناسب است.</p><p>backup channel را می‌توانید manual انتخاب کنید، یا automatic switching را انتخاب کنید تا ImgBed خودش suitable backup channel پیدا کند.</p><h2 id="backup-از-file-details" tabindex="-1">Backup از File Details <a class="header-anchor" href="#backup-از-file-details" aria-label="Permalink to &quot;Backup از File Details&quot;">​</a></h2><p>در admin panel، file details page را باز کنید و backup را بزنید.</p><p><img src="'+t+'" alt="Backup in file details" loading="lazy"></p><p>این روش برای backup گرفتن از یک file مهم به‌صورت on demand مناسب است.</p><p>پس از موفق شدن backup، file details page read sources موجود را نشان می‌دهد.</p><h2 id="batch-backup-با-selection" tabindex="-1">Batch Backup با Selection <a class="header-anchor" href="#batch-backup-با-selection" aria-label="Permalink to &quot;Batch Backup با Selection&quot;">​</a></h2><p>در admin panel چند file را انتخاب کنید و batch backup اجرا کنید.</p><p><img src="'+d+'" alt="Batch backup" loading="lazy"></p><p>این روش برای پردازش یک گروه file مناسب است.</p><p>Selection backup، file details backup و redundant backup زیر Other Settings همگی از یک backup system استفاده می‌کنند. فقط entry pointهایشان فرق دارد.</p><h2 id="switch-کردن-read-source-پس-از-backup" tabindex="-1">Switch کردن Read Source پس از Backup <a class="header-anchor" href="#switch-کردن-read-source-پس-از-backup" aria-label="Permalink to &quot;Switch کردن Read Source پس از Backup&quot;">​</a></h2><p>پس از complete شدن backup، file details page اجازه می‌دهد read source را switch کنید:</p><table tabindex="0"><thead><tr><th>Read Source</th><th>Description</th></tr></thead><tbody><tr><td>Primary channel</td><td>از original upload channel می‌خواند.</td></tr><tr><td>Backup channel</td><td>از backup channel می‌خواند.</td></tr></tbody></table><p><img src="'+r+'" alt="Switch read source after backup" loading="lazy"></p><p>visitors لازم نیست بدانند file از primary channel serve می‌شود یا backup channel.</p><p>هر read source که انتخاب کنید، برای later file access به preferred source تبدیل می‌شود.</p><h2 id="چه-زمانی-backup-skip-می‌شود" tabindex="-1">چه زمانی Backup Skip می‌شود <a class="header-anchor" href="#چه-زمانی-backup-skip-می‌شود" aria-label="Permalink to &quot;چه زمانی Backup Skip می‌شود&quot;">​</a></h2><p>موارد زیر هنگام backup skip می‌شوند. این‌ها error نیستند.</p><table tabindex="0"><thead><tr><th>Case</th><th>Why It Is Skipped</th></tr></thead><tbody><tr><td>Already backed up</td><td>file که قبلاً backup دارد دوباره backup نمی‌شود.</td></tr><tr><td>Primary and backup channels are the same</td><td>برای معنی‌دار بودن backup، copy باید در channel دیگری باشد.</td></tr><tr><td>No usable backup channel</td><td>alternative channel مناسبی وجود ندارد.</td></tr></tbody></table><p>خلاصه: backups باید به channel دیگری بروند و filesی که already backed-up هستند دوباره extra space مصرف نمی‌کنند.</p><h2 id="primary-channel-vs-backup-channel" tabindex="-1">Primary Channel vs Backup Channel <a class="header-anchor" href="#primary-channel-vs-backup-channel" aria-label="Permalink to &quot;Primary Channel vs Backup Channel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td>Primary channel</td><td>channelی که file اولین بار با آن upload شده.</td></tr><tr><td>Backup channel</td><td>channelی که redundant copy را ذخیره می‌کند.</td></tr><tr><td>Primary read source</td><td>file در حال حاضر از primary channel خوانده می‌شود.</td></tr><tr><td>Backup read source</td><td>file در حال حاضر از backup channel خوانده می‌شود.</td></tr></tbody></table><p>Primary و backup read sources از نظر user-facing behavior یکسان هستند.</p><p>تا وقتی backup file available باشد، پس از switch به backup read source، images، videos و download links همچنان کار می‌کنند.</p><h2 id="هنگام-delete-شدن-file-چه-می‌شود" tabindex="-1">هنگام Delete شدن File چه می‌شود <a class="header-anchor" href="#هنگام-delete-شدن-file-چه-می‌شود" aria-label="Permalink to &quot;هنگام Delete شدن File چه می‌شود&quot;">​</a></h2><p>وقتی file delete شود، ImgBed هم primary file و هم backup file را delete می‌کند.</p>',37)])])}const g=c(l,[["render",u]]);export{y as __pageData,g as default};
